SELECT p.privateClassOrderId,p.buyCount,p.createdDate,p.status,p.imgUrl,p.className,concat(p.price,'') as price
FROM private_class_order p
WHERE p.coachId = #{coachId}
ORDER BY p.createdDate desc

    limit #{offset}, #{limit}

SELECT COUNT(1)
FROM private_class_order p
WHERE p.coachId = #{coachId}

